import{_ as r,c as i,o as t,a5 as e,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.2.6：新增 D/Clojure 代码格式化、GitLab 改进","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.6.md","filePath":"changelog/v1.2.6.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.2.6.md"};function n(h,l,d,s,c,p){return t(),i("div",null,[...l[0]||(l[0]=[e('<h1 id="v1-2-6-新增-d-clojure-代码格式化、gitlab-改进" tabindex="-1">v1.2.6：新增 D/Clojure 代码格式化、GitLab 改进 <a class="header-anchor" href="#v1-2-6-新增-d-clojure-代码格式化、gitlab-改进" aria-label="Permalink to “v1.2.6：新增 D/Clojure 代码格式化、GitLab 改进”">​</a></h1><p><strong>发布日期</strong>：2026年2月16日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新<strong>新增了 D 语言和 Clojure 的代码格式化器</strong>，并改进了 GitLab 的登录体验。</p><hr><h2 id="新功能-d-语言格式化-dfmt" tabindex="-1">新功能：D 语言格式化（dfmt） <a class="header-anchor" href="#新功能-d-语言格式化-dfmt" aria-label="Permalink to “新功能：D 语言格式化（dfmt）”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 D 语言文件添加了 <strong>dfmt</strong> 格式化器支持。</p><h3 id="dfmt-是什么" tabindex="-1">dfmt 是什么？ <a class="header-anchor" href="#dfmt-是什么" aria-label="Permalink to “dfmt 是什么？”">​</a></h3><p>dfmt 是 D 语言的<strong>官方代码格式化工具</strong>，可以自动调整代码缩进、空格、换行等，让代码风格统一。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><p>当你在编辑 <code>.d</code> 文件时，OpenCode 会自动使用 dfmt 格式化代码。</p><p>如果你想让代码自动格式化，可以在配置文件中启用：</p>',14),a("div",{class:"language-json"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"json"),a("pre",null,[a("code",{"v-pre":""},`{
  "formatters": {
    "d": "dfmt"
  }
}`)])],-1),e('<h3 id="d-语言是什么" tabindex="-1">D 语言是什么？ <a class="header-anchor" href="#d-语言是什么" aria-label="Permalink to “D 语言是什么？”">​</a></h3><p>D 语言是一门系统级编程语言，兼具 C++ 的性能和 Python 的易用性。它用于：</p><ul><li>高性能应用</li><li>游戏开发</li><li>系统编程</li></ul><hr><h2 id="新功能-clojure-格式化-cljfmt" tabindex="-1">新功能：Clojure 格式化（cljfmt） <a class="header-anchor" href="#新功能-clojure-格式化-cljfmt" aria-label="Permalink to “新功能：Clojure 格式化（cljfmt）”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 Clojure 文件添加了 <strong>cljfmt</strong> 格式化器支持。</p><h3 id="cljfmt-是什么" tabindex="-1">cljfmt 是什么？ <a class="header-anchor" href="#cljfmt-是什么" aria-label="Permalink to “cljfmt 是什么？”">​</a></h3><p>cljfmt 是 Clojure 的代码格式化工具，基于 core.style 的风格指南。</p><h3 id="如何使用-1" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to “如何使用？”">​</a></h3><p>编辑 <code>.clj</code> 或 <code>.cljs</code> 文件时，OpenCode 会自动使用 cljfmt 格式化。</p>',11),a("div",{class:"language-json"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"json"),a("pre",null,[a("code",{"v-pre":""},`{
  "formatters": {
    "clojure": "cljfmt"
  }
}`)])],-1),e('<h3 id="clojure-是什么" tabindex="-1">Clojure 是什么？ <a class="header-anchor" href="#clojure-是什么" aria-label="Permalink to “Clojure 是什么？”">​</a></h3><p>Clojure 是运行在 JVM 平台上的 Lisp 方言，以<strong>简洁</strong>和<strong>函数式编程</strong>著称。它用于：</p><ul><li>数据处理</li><li>Web 开发</li><li>并发编程</li></ul><hr><h2 id="新功能-gitlab-中途-token-刷新" tabindex="-1">新功能：GitLab 中途 token 刷新 <a class="header-anchor" href="#新功能-gitlab-中途-token-刷新" aria-label="Permalink to “新功能：GitLab 中途 token 刷新”">​</a></h2><h3 id="这次更新了什么-2" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-2" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>升级了 GitLab 提供商和认证插件，现在支持<strong>会话中途刷新 token</strong>，不需要重新登录。</p><h3 id="这有什么好处" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>之前，如果 GitLab 的 token 过期了，你需要重新登录一次。现在：</p><ul><li>Token 即将过期时会自动刷新</li><li>不会中断你的工作</li><li>体验更流畅</li></ul><h3 id="什么时候会刷新" tabindex="-1">什么时候会刷新？ <a class="header-anchor" href="#什么时候会刷新" aria-label="Permalink to “什么时候会刷新？”">​</a></h3><ul><li>Token 即将过期时（通常每小时）</li><li>不会影响正在进行的对话</li></ul><hr><h2 id="新功能-google-vertex-openai-兼容端点" tabindex="-1">新功能：Google Vertex OpenAI 兼容端点 <a class="header-anchor" href="#新功能-google-vertex-openai-兼容端点" aria-label="Permalink to “新功能：Google Vertex OpenAI 兼容端点”">​</a></h2><h3 id="这次更新了什么-3" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-3" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 Google Vertex 提供商添加了 <strong>OpenAI 兼容端点</strong>支持。</p><h3 id="这有什么好处-1" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-1" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>如果你有支持 OpenAI API 格式的工具或服务，现在可以用它来访问 Google Vertex 的模型。</p><p><strong>简单说</strong>：更灵活的模型访问方式。</p><hr><h2 id="新功能-venice-参数支持" tabindex="-1">新功能：Venice 参数支持 <a class="header-anchor" href="#新功能-venice-参数支持" aria-label="Permalink to “新功能：Venice 参数支持”">​</a></h2><h3 id="这次更新了什么-4" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-4" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 Venice 提供商添加了更多参数支持：</p><ul><li>temperature</li><li>topP</li><li>topK</li><li>smallOption</li></ul><h3 id="这有什么好处-2" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处-2" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>可以更精细地控制 Venice 模型的输出：</p><ul><li><strong>temperature</strong>：控制创意程度（越高越随机）</li><li><strong>topP</strong>：核采样参数</li><li><strong>topK</strong>：限制候选词数量</li><li><strong>smallOption</strong>：小模型选项</li></ul><hr><h2 id="问题修复-环境变量优先级" tabindex="-1">问题修复：环境变量优先级 <a class="header-anchor" href="#问题修复-环境变量优先级" aria-label="Permalink to “问题修复：环境变量优先级”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 Google Vertex AI 配置中，环境变量可能会覆盖用户配置，导致设置不生效。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在<strong>用户定义的变量优先于环境变量</strong>，你的配置不会被覆盖。</p><hr><h2 id="问题修复-多余的-llm-调用" tabindex="-1">问题修复：多余的 LLM 调用 <a class="header-anchor" href="#问题修复-多余的-llm-调用" aria-label="Permalink to “问题修复：多余的 LLM 调用”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>每条消息都会调用 LLM 生成标题，造成不必要的 API 调用和延迟。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>移除了不必要的每消息标题 LLM 调用，提高了响应速度。</p><hr><h2 id="新功能-tui-数据库迁移命令" tabindex="-1">新功能：TUI 数据库迁移命令 <a class="header-anchor" href="#新功能-tui-数据库迁移命令" aria-label="Permalink to “新功能：TUI 数据库迁移命令”">​</a></h2><h3 id="这次更新了什么-5" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-5" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在 TUI 模式中添加了数据库迁移命令，可以将 JSON 存储迁移到 SQLite。</p><h3 id="如何使用-2" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-2" aria-label="Permalink to “如何使用？”">​</a></h3><p>在 TUI 界面中输入 <code>/migrate</code> 命令即可触发迁移。</p><p><strong>注意</strong>：迁移过程可能需要一些时间，取决于数据量。</p><hr><h2 id="新功能-attach-命令扩展" tabindex="-1">新功能：attach 命令扩展 <a class="header-anchor" href="#新功能-attach-命令扩展" aria-label="Permalink to “新功能：attach 命令扩展”">​</a></h2><h3 id="这次更新了什么-6" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-6" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 <code>attach</code> 命令添加了 <code>--continue</code> 和 <code>--fork</code> 标志。</p><h3 id="如何使用-3" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用-3" aria-label="Permalink to “如何使用？”">​</a></h3><ul><li><code>opencode attach --continue</code>：继续之前的会话</li><li><code>opencode attach --fork</code>：复制当前会话并创建新分支</li></ul><hr><h2 id="问题修复-桌面端-linux-显示" tabindex="-1">问题修复：桌面端 Linux 显示 <a class="header-anchor" href="#问题修复-桌面端-linux-显示" aria-label="Permalink to “问题修复：桌面端 Linux 显示”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 Linux 上使用桌面应用时，Wayland/X11 后端和装饰策略不一致。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>统一了 Linux 的显示后端和窗口装饰策略，体验更一致。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 D 或 Clojure</td><td>✅ 升级</td></tr><tr><td>使用 GitLab</td><td>✅ 升级</td></tr><tr><td>桌面端 Linux 用户</td><td>✅ 升级</td></tr><tr><td>想提升响应速度</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',62),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),e('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>添加 dfmt 格式化器支持 D 语言文件</li><li>升级 GitLab 提供商和认证插件以支持中途 token 刷新</li><li>移除不必要的每消息标题 LLM 调用</li><li>Google Vertex AI 配置中用户定义的变量优先于环境变量</li><li>为 Google Vertex 提供商添加 OpenAI 兼容端点支持</li><li>为 Venice 添加 temperature、topP、topK 和 smallOption 参数支持</li><li>添加 cljfmt 格式化器支持 Clojure 文件</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>使用服务器目录路径处理提示中的文件引用</li><li>添加数据库迁移命令，将 JSON 存储转换为 SQLite</li><li>为 attach 命令添加 --continue 和 --fork 标志</li><li>修复 TUI 中不准确的提示</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>统一 Linux Wayland/X11 后端和装饰策略</li><li>在桌面应用中使用 process-wrap 库替代手动 job 对象处理</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 12 位社区贡献者：</p><ul><li>@finalfantasia：添加 cljfmt 格式化器</li><li>@pkx07：修正中文翻译中的专有名词</li><li>@Brendonovich：使用 process-wrap 替代手动 job 对象</li><li>@dpuyosa：为 Venice 添加参数支持</li><li>@bnema：统一 Linux 显示后端</li><li>@leehack：为 google-vertex 添加 OpenAI 兼容端点</li><li>@hobostay：修正俄语文档翻译错误</li><li>@rmk40：移除不必要的 LLM 标题调用</li><li>@imanolmzd-svg：修复不准确的提示</li><li>@vglafirov：升级 GitLab 提供商</li><li>@OpeOginni：修复文件引用路径问题</li><li>@burner：添加 dfmt 格式化器</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const f=r(o,[["render",n]]);export{m as __pageData,f as default};
